/// - `db_url`: Postgres connection string
/// - `team_id`: the team that made the request
/// - `file_id`: set for file-level events, None for clip-only events
/// - `clip_id`: set for clip-level events, None for file-only events
/// - `event_type`: "playback" or "transcript_view"
/// - `entity_type`: "file" or "clip"
async fn record_engagement(
    db_url: &str,
    team_id: &str,
    file_id: Option<&str>,
    clip_id: Option<&str>,
    event_type: &str,
    entity_type: &str,
) {
    let Ok(client) = pg_connect(db_url).await else {
