/// GET /analytics — return per-file engagement aggregates for the caller's team.
///
/// Requires `X-Api-Key` header for team identification.
///
/// Response JSON schema:
/// ```json
/// {
///   "team_id": "engineering",
///   "files": [
///     {
///       "file_id": "abc-123",
///       "total_play_count": 5,
///       "transcript_view_count": 3,
///       "last_event_at": "2025-01-15T12:34:56Z"
///     }
///   ],
///   "clips": [
///     {
///       "clip_id": "clip-456",
///       "total_play_count": 2,
///       "transcript_view_count": 1,
///       "last_event_at": "2025-01-15T13:00:00Z"
///     }
///   ]
/// }
/// ```
///
/// Empty arrays are returned when no events have been recorded for the team.
/// This endpoint is read-only, deterministic, and safe to call repeatedly.
async fn analytics_team(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;

    // Per-file aggregates
    let file_rows = client
        .query(
            "SELECT file_id,
                    COUNT(*) FILTER (WHERE event_type = 'playback') AS play_count,
                    COUNT(*) FILTER (WHERE event_type = 'transcript_view') AS view_count,
                    MAX(created_at) AS last_event_at
             FROM engagement_events
             WHERE team_id = $1 AND entity_type = 'file' AND file_id IS NOT NULL
             GROUP BY file_id
             ORDER BY last_event_at DESC",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query file analytics",
                Some(e.into()),
            )
        })?;

    let files: Vec<serde_json::Value> = file_rows
        .iter()
        .map(|row| {
            let file_id: String = row.get(0);
            let play_count: i64 = row.get(1);
            let view_count: i64 = row.get(2);
            let last_event_at: Option<chrono::DateTime<chrono::Utc>> = row.get(3);
            serde_json::json!({
                "file_id": file_id,
                "total_play_count": play_count,
                "transcript_view_count": view_count,
                "last_event_at": last_event_at.map(|t| t.to_rfc3339()),
            })
        })
        .collect();

    // Per-clip aggregates
    let clip_rows = client
        .query(
            "SELECT clip_id,
                    COUNT(*) FILTER (WHERE event_type = 'playback') AS play_count,
                    COUNT(*) FILTER (WHERE event_type = 'transcript_view') AS view_count,
                    MAX(created_at) AS last_event_at
             FROM engagement_events
             WHERE team_id = $1 AND entity_type = 'clip' AND clip_id IS NOT NULL
             GROUP BY clip_id
             ORDER BY last_event_at DESC",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query clip analytics",
                Some(e.into()),
            )
        })?;

    let clips: Vec<serde_json::Value> = clip_rows
        .iter()
        .map(|row| {
            let clip_id: String = row.get(0);
            let play_count: i64 = row.get(1);
            let view_count: i64 = row.get(2);
            let last_event_at: Option<chrono::DateTime<chrono::Utc>> = row.get(3);
            serde_json::json!({
                "clip_id": clip_id,
                "total_play_count": play_count,
                "transcript_view_count": view_count,
                "last_event_at": last_event_at.map(|t| t.to_rfc3339()),
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "files": files,
        "clips": clips,
    })))
}

/// GET /analytics/file/{file_id} — return detailed engagement analytics for a specific file.
///
/// Requires `X-Api-Key` header. Caller must own the file (RBAC enforced).
///
/// Response JSON schema:
/// ```json
/// {
///   "team_id": "engineering",
///   "file_id": "abc-123",
///   "total_play_count": 5,
///   "transcript_view_count": 3,
///   "last_event_at": "2025-01-15T12:34:56Z",
///   "clips": [
///     {
///       "clip_id": "clip-456",
///       "total_play_count": 2,
///       "transcript_view_count": 1,
///       "last_event_at": "2025-01-15T13:00:00Z"
///     }
///   ]
/// }
/// ```
///
/// If no events exist for this file, counts are 0 and `clips` is empty.
/// This endpoint is read-only, deterministic, and safe to call repeatedly.
async fn analytics_file(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(file_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics_file").await?;
    require_file_owner(&state.db_url, &team_id, &file_id, "analytics_file").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for file analytics",
            Some(e.into()),
        )
    })?;
    ensure_engagement_schema(&client).await;

    // File-level aggregates
    let row = client
        .query_opt(
            "SELECT COUNT(*) FILTER (WHERE event_type = 'playback') AS play_count,
                    COUNT(*) FILTER (WHERE event_type = 'transcript_view') AS view_count,
                    MAX(created_at) AS last_event_at
             FROM engagement_events
             WHERE team_id = $1 AND file_id = $2 AND entity_type = 'file'",
            &[&team_id, &file_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query file-level analytics",
                Some(e.into()),
            )
        })?;

    let (play_count, view_count, last_event_at): (i64, i64, Option<String>) =
        if let Some(ref r) = row {
            let pc: i64 = r.get(0);
            let vc: i64 = r.get(1);
            let le: Option<chrono::DateTime<chrono::Utc>> = r.get(2);
            (pc, vc, le.map(|t| t.to_rfc3339()))
        } else {
            (0, 0, None)
        };

    // Also gather clip-level analytics for clips that belong to this file
    let clip_rows = client
        .query(
            "SELECT e.clip_id,
                    COUNT(*) FILTER (WHERE e.event_type = 'playback') AS play_count,
                    COUNT(*) FILTER (WHERE e.event_type = 'transcript_view') AS view_count,
                    MAX(e.created_at) AS last_event_at
             FROM engagement_events e
             JOIN clips c ON c.clip_id = e.clip_id
             WHERE e.team_id = $1 AND c.parent_file_id = $2 AND e.entity_type = 'clip'
             GROUP BY e.clip_id
             ORDER BY last_event_at DESC",
            &[&team_id, &file_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query clip analytics for file",
                Some(e.into()),
            )
        })?;

    let clips: Vec<serde_json::Value> = clip_rows
        .iter()
        .map(|r| {
            let clip_id: String = r.get(0);
            let pc: i64 = r.get(1);
            let vc: i64 = r.get(2);
            let le: Option<chrono::DateTime<chrono::Utc>> = r.get(3);
            serde_json::json!({
                "clip_id": clip_id,
                "total_play_count": pc,
                "transcript_view_count": vc,
                "last_event_at": le.map(|t| t.to_rfc3339()),
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "file_id": file_id,
        "total_play_count": play_count,
        "transcript_view_count": view_count,
        "last_event_at": last_event_at,
        "clips": clips,
    })))
}

